# -- Helpers --
import textwrap as _tw

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()


def _secret_for_question(index):
    secret = _open_secret(QUESTION_SECRETS[index - 1], "argv-explorer:question:" + str(index))
    if secret is None:
        print("  [error] Could not open question quiz-data -- contact your instructor.")
        sys.exit(1)
    return secret

def _ask(q, index, total):
    secret = _secret_for_question(index)
    print(f"\n  Q{index:02}/{total:02}  {q['prompt']}")
    print(f"           Hint: {q['hint']}")
    attempts = 0
    while True:
        raw = input("  Your answer: ").strip()
        if not raw:
            continue
        if raw == secret["answer"]:
            if attempts > 0:
                for ln in _wrap(secret.get("explanation", "")):
                    print(ln)
            else:
                print(f"  Correct.  {secret.get('explanation', '')}")
            return raw
        attempts += 1
        _show_wrong(raw, secret.get("wrong") or {})
        print("           Trace through the function step by step and try again.")


def main():
    _banner("Activity: argv Explorer")
    print()
    input("  Press Enter to begin...")

    answers = []
    total = len(QUESTIONS)
    for i, q in enumerate(QUESTIONS, 1):
        answers.append(_ask(q, i, total))

    print()
    print("  All correct.")
    passphrase = _decrypt(_BLOB, answers)
    if passphrase is None:
        print("  [error] Decryption failed -- contact your instructor.")
        sys.exit(1)
    _show_passphrase(passphrase)


if __name__ == "__main__":
    main()
